scwin.onpageload = async function () {
  scwin.strCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
  scwin.strPreDate = $c.date.addDate($p, scwin.strCurDate, -2);
  scwin.userId = $c.ses.getUserId();
  scwin.p_lobranCd = $c.ses.getLobranCd();
  scwin.p_lobranNm = $c.ses.getLobranNm();
  let now = new Date();
  let hof = String(now.getHours()).padStart(2, "0");
  let mm = String(now.getMinutes()).padStart(2, "0");
  scwin.currentTime = hof + mm;
  scwin.params = $c.data.getParameter($p);
  if (scwin.params != null) {
    scwin.v_linkcheck = scwin.params["linkcheck"] || "0";
    scwin.v_kcomcd = scwin.params["kcomcd"] || "";
    scwin.v_blno = scwin.params["blno"] || "";
    scwin.v_mhno = scwin.params["mhno"] || "";
    scwin.v_bkno = scwin.params["bkno"] || "";
  }
  scwin.f_DefaultValue();
};
scwin.f_DefaultValue = async function () {
  scwin.f_Set("INIT");
  scwin.f_Check();
  scwin.f_getParametrSetting(scwin.v_linkcheck);
};
scwin.f_Check = async function () {
  if (scwin.statusFlag == "I") {
    acb_hhbltype.setSelectedIndex(0);
    acb_hhpcgb.setSelectedIndex(1);
    acb_hhstype.setSelectedIndex(0);
    acb_hhcoload.setSelectedIndex(0);
    rd_hhdanggb.setValue("N");
    rd_hhmnfgb.setValue("I");
    rd_hhcnrggb.setValue("C");
    rd_hhntrggb.setValue("C");
    acb_hhwaregb.setSelectedIndex(2);
  } else if (scwin.statusFlag == "C") {
    acb_hhbltype.setSelectedIndex(0);
    acb_hhpcgb.setSelectedIndex(1);
    acb_hhstype.setSelectedIndex(0);
    acb_hhcoload.setSelectedIndex(0);
    rd_hhdanggb.setValue("N");
    rd_hhmnfgb.setValue("I");
    rd_hhcnrggb.setValue("C");
    rd_hhntrggb.setValue("C");
    acb_hhwaregb.setSelectedIndex(2);
    acb_shhcucd.setValue("USD");
    acb_phhcucd.setValue("USD");
    acb_bhhcucd.setValue("USD");
  }
};
scwin.f_getParametrSetting = async function (gubun) {
  switch (gubun) {
    case "0":
      break;
    case "1":
      scwin.mhnoFlag = "1";
      if (scwin.v_blno == "null") {
        cnd_ed_hhblno.setValue("");
        cnd_ed_hhblno.setFocus();
        return false;
      }
      scwin.hd_kcomcd = scwin.v_kcomcd;
      cnd_ed_hhblno.setValue(scwin.v_blno);
      break;
    case "2":
      scwin.mhnoFlag = "1";
      if (scwin.v_blno == "null") {
        cnd_ed_hhblno.setValue("");
        cnd_ed_hhblno.setFocus();
        return false;
      }
      scwin.hd_kcomcd = scwin.v_kcomcd;
      cnd_ed_hhblno.setValue(scwin.v_blno);
      break;
    case "4":
      scwin.f_Create();
      ed_hhbkgno.setValue(scwin.v_bkno);
      break;
  }
};
scwin.f_Set = async function (gubun) {
  switch (gubun) {
    case "INIT":
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Retrieve]);
      scwin.statusFlag = "I";
      break;
    case "RETRIEVE":
      $c.gus.cfDisableKeyData($p);
      gr_ocContList.setReadOnly("grid", true);
      gr_selling.setReadOnly("grid", true);
      gr_partner.setReadOnly("grid", true);
      gr_buying.setReadOnly("grid", true);
      if (scwin.statusFlag == "C") {
        // TODO: disable update buttons
      } else {
        // TODO: enable update buttons
      }
      scwin.statusFlag = "";
      break;
    case "CREATE":
      $c.gus.cfEnableKeyData($p);
      gr_ocContList.setReadOnly("grid", false);
      gr_selling.setReadOnly("grid", false);
      gr_partner.setReadOnly("grid", false);
      gr_buying.setReadOnly("grid", false);
      scwin.statusFlag = "C";
      break;
    case "UPDATE":
      gr_ocContList.setReadOnly("grid", false);
      gr_selling.setReadOnly("grid", false);
      gr_partner.setReadOnly("grid", false);
      gr_buying.setReadOnly("grid", false);
      scwin.statusFlag = "U";
      break;
    case "SAVE":
      scwin.f_Set("RETRIEVE");
      break;
  }
};
