scwin.f_Save = async function () {
  if (ds_houseblList.isUpdated() || ds_ocContList.isUpdated() || ds_selling.isUpdated() || ds_partner.isUpdated() || ds_buying.isUpdated()) {
    if (scwin.f_validate() && scwin.f_validate_freight() && scwin.f_JobCloseYn()) {
      let chk = await $c.win.confirm($p, E_MSG_CM_CRM_001);
      if (chk) {
        if (scwin.statusFlag == "C") {
          if (cnd_ed_hhblno.getValue().trim() == "") {
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House No"]);
            return;
          }
          dma_retrieveBooking.set("kcomcd", scwin.hd_kcomcd);
          dma_retrieveBooking.set("bkEta", ica_hheta.getValue());
          dma_retrieveBooking.set("cfs", acb_hhbltype.getValue());
          await $c.sbm.execute($p, sbm_retrievebookingNo);
          ed_hhbkgno.setValue(ds_retrieveNo.getCellData(0, "bkNo"));
          scwin.f_autoCreateDoorOrderInfo();
          let row = ds_houseblList.getRowPosition();
          ds_houseblList.setCellData(row, "kcomcd", scwin.hd_kcomcd);
          ds_houseblList.setCellData(row, "hhblno", cnd_ed_hhblno.getValue());
          ds_houseblList.setCellData(row, "hhio", scwin.hd_hhio);
          ds_houseblList.setCellData(row, "inpid", scwin.userId);
          ds_houseblList.setCellData(row, "hhmitem1", "일반화물");
          ds_houseblList.setCellData(row, "hhbkgno", ed_hhbkgno.getValue());
          ds_houseblList.setCellData(row, "hhbkgseq", "01");
          for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
            ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
            ds_ocContList.setCellData(i, "mchblno", cnd_ed_hhblno.getValue());
            ds_ocContList.setCellData(i, "inpid", scwin.userId);
            ds_ocContList.setRowStatus(i, "C");
          }
          ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
          ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkNo", ds_retrieveNo.getCellData(0, "bkNo"));
          ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "cfs", acb_hhbltype.getValue());
          ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);
          for (let i = 0; i < ds_selling.getRowCount(); i++) {
            ds_selling.setCellData(i, "blNo", cnd_ed_hhblno.getValue());
            ds_selling.setCellData(i, "odrNo", "");
          }
          for (let i = 0; i < ds_partner.getRowCount(); i++) {
            ds_partner.setCellData(i, "blNo", cnd_ed_hhblno.getValue());
            ds_partner.setCellData(i, "odrNo", "");
          }
          for (let i = 0; i < ds_buying.getRowCount(); i++) {
            ds_buying.setCellData(i, "blNo", cnd_ed_hhblno.getValue());
            ds_buying.setCellData(i, "odrNo", "");
          }
        }
        ds_houseblList.setCellData(ds_houseblList.getRowPosition(), "chk", "T");
        await $c.sbm.execute($p, sbm_save);
      }
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["House B/L"]);
    await $c.sbm.execute($p, sbm_save);
  }
};
scwin.f_Delete = async function () {
  scwin.f_invoiceCheck();
  if (scwin.invoiceCheck == "1") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
    return;
  }
  let chk = await $c.win.confirm($p, E_MSG_CM_CRM_004);
  if (chk) {
    ds_houseblList.removeAll();
    ds_containerBookingList.removeAll();
    await $c.sbm.execute($p, sbm_delete);
    cnd_ed_hhblno.setValue("");
    ds_houseblList.removeAll();
    ds_ocContList.removeAll();
    ds_slipTax.removeAll();
    ds_ocProfitList.removeAll();
    ds_hitekContents.removeAll();
    cnd_ed_hhblno.setFocus();
    scwin.f_Set("INIT");
  }
};
scwin.f_FreightDelete = async function () {
  if (ds_selling.getRowCount() == 0 && ds_partner.getRowCount() == 0 && ds_buying.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Freight Information"]);
    return;
  }
  scwin.f_invoiceCheck();
  if (scwin.invoiceCheck == "1") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
    return;
  }
  let chk = await $c.win.confirm($p, MSG_CM_CRM_004);
  if (chk) {
    ds_selling.removeAll();
    ds_partner.removeAll();
    ds_buying.removeAll();
    await $c.sbm.execute($p, sbm_deleteFreight);
    ds_selling.removeAll();
    ds_partner.removeAll();
    ds_buying.removeAll();
    cnd_ed_hhblno.setFocus();
    scwin.f_Set("INIT");
  }
};
scwin.f_Cancel = async function () {
  cnd_ed_hhblno.setFocus();
  if (scwin.statusFlag == "C") {
    scwin.f_Set("INIT");
  } else {
    scwin.f_Set("RETRIEVE");
    ds_houseblList.undoAll();
    ds_ocContList.undoAll();
    await $c.sbm.execute($p, sbm_retrieve);
  }
};
