scwin.f_validate = async function () {
  if (ica_hheta.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["ETA"]);
    ica_hheta.setFocus();
    return false;
  }
  if ($c.date.diffDate($p, scwin.strCurDate, ica_hheta.getValue()) > 90) {
    await $c.win.alert($p, "ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    ica_hheta.setFocus();
    return false;
  }
  if ($c.date.diffDate($p, ica_hhetd.getValue(), ica_hheta.getValue()) > 149) {
    await $c.win.alert($p, "ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
    ica_hhetd.setFocus();
    return false;
  }
  if (acb_contractno.getValue() == "") {
    await $c.win.alert($p, "계약은 필수항목 입니다. Customer를 확인하세요.");
    return false;
  }
  return true;
};
