scwin.f_ContractInfo = async function () {
  ds_ctrtNo.removeAll();
  ds_ctrtNo.insertRow();
  dma_retrieveCtrtClnt.set("ctrtClntNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhactcust"));
  dma_retrieveCtrtClnt.set("scDate", ica_hheta.getValue().trim());
  dma_retrieveCtrtClnt.set("ctrtDtYn", "1");
  dma_retrieveCtrtClnt.set("ctrtDistrictCd", "ZZA");
  dma_retrieveCtrtClnt.set("impExpDomesticClsCd", "I");
  if (acb_hhbltype.getValue() != "B") {
    dma_retrieveCtrtClnt.set("bizDivCntrYn", "1");
  } else {
    dma_retrieveCtrtClnt.set("bizDivBulkYn", "1");
  }
  await $c.sbm.execute($p, sbm_retrieveCtrtClnt);
  acb_contractno.setSelectedIndex(0);
  if (ds_ctrtNo.getRowCount() == 0) {
    dma_retrieveCtrtClnt.set("ctrtClntNo", "999908");
    await $c.sbm.execute($p, sbm_retrieveCtrtClnt);
    acb_contractno.setSelectedIndex(0);
  }
};
