        ds_buying.setCellData(row3, "mblHblCls", "H");
        ds_buying.setCellData(row3, "seaAirCls", "S");
        ds_buying.setCellData(row3, "ppccCls", scwin.hd_hhpcgb);
        ds_buying.setCellData(row3, "inpid", scwin.userId);
        ds_buying.setCellData(row3, "pchsTyp", "1");
