scwin.f_FdeleteRow = async function (disGubun) {
  let tmp;
  switch (disGubun) {
    case 1:
      tmp = ds_selling;
      for (let i = tmp.getRowCount() - 1; i >= 0; i--) {
        if (tmp.getCellData(i, "chk") == "T" || i == tmp.getRowPosition()) {
          if (tmp.getCellData(i, "certiNo") == "") {
            tmp.removeRow(i);
          } else {
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
            return;
          }
        }
      }
      break;
    case 2:
      tmp = ds_partner;
      for (let i = tmp.getRowCount() - 1; i >= 0; i--) {
        if (tmp.getCellData(i, "chk") == "T" || i == tmp.getRowPosition()) {
          if (tmp.getCellData(i, "certiNo") == "") {
            tmp.removeRow(i);
          } else {
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
            return;
          }
        }
      }
      break;
    case 3:
      tmp = ds_buying;
      for (let i = tmp.getRowCount() - 1; i >= 0; i--) {
        if (tmp.getCellData(i, "chk") == "T" || i == tmp.getRowPosition()) {
          if (tmp.getCellData(i, "pchsCertiNo") == "") {
            tmp.removeRow(i);
          } else {
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
            return;
          }
        }
      }
      break;
  }
};
scwin.f_FcancelRow = function (disGubun) {
  switch (disGubun) {
    case 1:
      ds_selling.undoAll();
      break;
    case 2:
      ds_partner.undoAll();
      break;
    case 3:
      ds_buying.undoAll();
      break;
  }
};
